{code}
  /**
   * Places apps in queues by username of the submitter if username matched by pattern
   */
  public static class UserMatch extends QueuePlacementRule {

    private Pattern pattern;

    @Override
    public QueuePlacementRule initialize(boolean create, Map<String, String> args) {
      super.initialize(create, args);
      String patternArg = args == null ? ".*" : args.get("pattern");
      if (patternArg == null)
        patternArg = ".*";
      pattern = Pattern.compile(patternArg);
      return this;
    }

    @Override
    protected String getQueueForApp(String requestedQueue,
                                    String user, Groups groups, Collection<String> configuredQueues) {
      if (pattern.matcher(user).matches())
        return prefix + user;
      else
        return "";
    }

    @Override
    public boolean isTerminal() {
      return false;
    }
  }
